				'<a href="' . esc_url( self::get_welcome_step() ) . '">',
				'</a>'
			)

array_map(
					function ( $v, $k ) {
						if ( is_array( $v ) ) {
							if ( 'membership' === $k ) {
								$membership_names = self::flatten_memberships_to_string( $v );

								return ucfirst( $k ) . ' is ' . $membership_names;
							}

							return ucfirst( $k ) . ' is ' . ucwords( implode( ', ', $v ) );
						} else {
							return ucfirst( $k ) . ' is ' . ucfirst( $v );
						}
					},
					$array,
					array_keys( $array )
				)

array_map(
